INSERT INTO subjects (slug, name, icon, description, active) VALUES
('shrm-scp', 'SHRM-SCP', '👔', 'SHRM-SCP Senior Certified Professional Exam', true);
INSERT INTO questions (subject_slug, domain, question_text, options, correct_index, explanation) VALUES
('shrm-scp', 'Acuity', 'An HR leader identifies that several high-performing employees are leaving the organization within 18 months of promotion. What is the BEST first step to address this retention issue?', '["Conduct exit interviews and analyze departure patterns", "Implement a formal mentoring program for all promoted staff", "Create retention bonuses contingent on 2-year tenure", "Increase compensation for newly promoted employees"]'::jsonb, 0, 'Exit interviews and analysis of departure patterns provide data-driven insights into why employees are leaving, enabling targeted interventions. While mentoring and retention bonuses may help, diagnosis through analysis is the logical first step before implementing solutions.'),
('shrm-scp', 'Acuity', 'A manufacturing plant experiences a 35% increase in workplace injuries over the past quarter. Which metric would BEST help the HR leader understand the root cause?', '["Total injury frequency rate and correlation with staffing changes", "Lost workday injury frequency rate (LWIFR)", "Workers'' compensation claim denial rate", "Injury severity rate (ISR)"]'::jsonb, 0, 'Analyzing the total injury frequency rate alongside staffing changes (such as turnover, new hires, or overtime increases) allows the HR leader to identify contributing factors. While ISR and LWIFR are valuable metrics, they don''t directly reveal causation related to workforce changes.'),
('shrm-scp', 'Acuity', 'A company''s voluntary turnover rate has doubled from 8% to 16% over two years. Which stakeholder group should the HR leader engage FIRST to understand external market factors?', '["Terminated employees through detailed exit surveys", "Customers to gather feedback on service quality", "Industry peers and recruiters through stay interviews", "Finance team to review compensation competitiveness"]'::jsonb, 2, 'Engaging industry peers and recruiters provides critical external market context on competitive compensation, hiring trends, and industry-wide talent challenges. This helps distinguish between internal (company-specific) and external (market-wide) causes of turnover.'),
('shrm-scp', 'Acuity', 'An organization''s healthcare costs have increased 22% year-over-year while industry average is 12%. What is the MOST strategic HR intervention?', '["Conduct a claims analysis and implement targeted wellness programs", "Reduce healthcare coverage options to basic plans only", "Increase employee cost-sharing for prescription drugs", "Switch to a high-deductible health plan to shift costs to employees"]'::jsonb, 0, 'Conducting a claims analysis identifies patterns (obesity, stress-related illness, chronic disease prevalence) enabling targeted wellness interventions. This addresses root causes rather than simply shifting costs or reducing benefits, which can harm employee morale and retention.'),
('shrm-scp', 'Acuity', 'Performance data shows that 40% of employees in one department have underperformed for two consecutive review cycles, while other departments show 5% underperformance. What should HR investigate FIRST?', '["Department manager effectiveness and leadership style", "Individual employee capability and training needs", "Staffing levels and workload distribution", "Job design and alignment of role expectations"]'::jsonb, 0, 'A systemic pattern of underperformance in one department suggests a leadership or environmental issue rather than individual capability problems. The manager may lack coaching skills, have unclear expectations, or create a poor team dynamic. This requires investigation of the department manager and team environment.'),
('shrm-scp', 'Acuity', 'An HR leader discovers that the company''s offer acceptance rate has dropped from 85% to 62% in six months. Which analysis should be prioritized to identify the cause?', '["Review time-to-offer and application-to-hire cycle time", "Survey declined candidates about their decision factors", "Analyze competitor hiring activity in the region", "Compare current offer compensation to market benchmarks"]'::jsonb, 1, 'Surveying declined candidates provides direct insights into their decision-making. While benchmarking and process analysis are valuable, direct feedback from those who rejected offers reveals whether issues are compensation, role clarity, culture fit, or timing.'),
('shrm-scp', 'Acuity', 'An analysis of engagement survey results shows that new hires (0-6 months) score 25 percentage points lower on ''connection to company purpose'' than established employees. What is the BEST initial response?', '["Revise the orientation to include more cultural immersion", "Increase frequency of company all-hands meetings", "Create mentoring pairs between new hires and tenured employees", "Redesign the onboarding program to include purpose-driven content"]'::jsonb, 3, 'A 25-point gap in purpose connection among new hires indicates a direct onboarding gap. The primary fix should address onboarding content and messaging about purpose. While mentoring and cultural immersion are valuable, deliberately embedding purpose messaging in onboarding is the most direct intervention.'),
('shrm-scp', 'Acuity', 'Absenteeism rates are 4.8 days per employee annually, compared to industry benchmark of 3.2 days. Which root cause analysis approach would BEST identify the drivers?', '["Implement stricter attendance policies", "Review absence patterns by department, tenure, and shift", "Compare absenteeism to job satisfaction scores", "Survey all employees on their reasons for absences"]'::jsonb, 1, 'Analyzing absence patterns by department, tenure, and shift reveals clusters (e.g., high in manufacturing vs. office, or among specific tenure groups) that point to root causes. This segmented analysis is more revealing than broad surveys and provides actionable targeting.'),
('shrm-scp', 'Acuity', 'A company''s internal promotion rate is 15%, while industry benchmark is 28%. An HR leader wants to understand if this reflects poor internal talent development or if talent is being hired externally for strategic reasons. What data should be gathered?', '["Promotion pipeline by level and time-in-role; percentage of openings filled externally with rationale", "Performance ratings of all internal candidates considered for promotion", "Training and development spending per employee", "Salary comparison of internally promoted vs. externally hired employees"]'::jsonb, 0, 'Understanding the promotion pipeline (depth of internal candidates at each level) and the reasons for external hiring (strategic, specialized skills, culture shift) directly answers whether the issue is inadequate development or intentional strategy. This provides clarity on whether intervention is needed.'),
('shrm-scp', 'Acuity', 'Skill gap analysis reveals that 35% of managers lack proficiency in the new enterprise system, six months after implementation. What is the BEST diagnostic question to guide next steps?', '["Which managers should be replaced due to technology incompetence?", "How much additional training budget is required?", "What barriers prevent adoption—training quality, system usability, time allocation, or motivation?", "Should a mandatory training certification be implemented?"]'::jsonb, 2, 'Before implementing solutions, the root barrier must be identified. A 35% gap could stem from poor training design, system usability issues, lack of time to practice, or resistance to change. Each requires different interventions. Identifying the barrier is essential for effective remediation.'),
('shrm-scp', 'Acuity', 'An HR leader observes that referral hires have a 92% one-year retention rate, while general applicants have 71% retention. What is the MOST valuable next step?', '["Analyze characteristics of referral hires vs. applicant hires to understand retention drivers", "Implement a mandatory referral program for all employees", "Increase referral bonus amounts to encourage more referrals", "Close external recruiting channels and hire exclusively through referrals"]'::jsonb, 0, 'Understanding why referral hires have higher retention (cultural fit, realistic job previews through referrer, self-selection, peer connection) enables replication of those factors for all hires. This analysis can improve overall retention without over-indexing on referrals.'),
('shrm-scp', 'Acuity', 'Employee survey results show high dissatisfaction with work-life balance, yet exit interview data shows few departures cite balance as a reason. What is the MOST likely explanation?', '["Employees are exaggerating dissatisfaction in anonymous surveys", "High performers are leaving due to balance while surveys represent lower performers who stay", "The survey question was poorly worded and should be revised", "Work-life balance dissatisfaction is causing disengagement, not departure"]'::jsonb, 1, 'Survey respondents and departure cohorts differ—high performers may be more likely to leave for better-balanced roles elsewhere, while those with fewer options stay despite dissatisfaction. This disconnect points to a retention risk among top talent that may not appear in exit interviews.'),
('shrm-scp', 'Acuity', 'A manufacturing facility''s supervisor-to-worker ratio is 1:28, compared to the company''s target of 1:15. What data should be analyzed to determine if additional supervisors are needed?', '["Industry average supervisor ratios", "Labor cost as a percentage of revenue", "Employee satisfaction scores for supervision and support", "Supervisor workload assessment, safety incident rates, and production defect rates"]'::jsonb, 3, 'The appropriate supervisor ratio depends on workload intensity and outcomes. Higher accident rates, quality defects, or documented supervisor burnout indicate inadequate staffing. Industry averages and cost alone don''t account for facility-specific demands and current performance gaps.'),
('shrm-scp', 'Acuity', 'Post-acquisition integration data shows that 28% of acquired company employees have left within 12 months, compared to 12% from the acquiring company. What is the FIRST analysis to conduct?', '["Implement retention bonuses for critical acquired company talent", "Compare salary and benefits between the two companies", "Analyze retention rates by tenure and role in the acquired company", "Conduct culture assessment and communication effectiveness review"]'::jsonb, 2, 'Understanding which roles and tenure groups are leaving provides insight into whether departures reflect job insecurity (leadership/middle management), role redundancy, or integration challenges. This segmentation guides targeted retention and integration strategies.'),
('shrm-scp', 'Acuity', 'An HR leader discovers that performance ratings have been inflated across the board (85% of employees rated as ''meets/exceeds expectations''), making succession planning impossible. What is the underlying HR process issue?', '["Employees are truly high performers and ratings are accurate", "Managers lack training in objective performance assessment", "The performance management system does not enforce a differentiation requirement", "Performance documentation is insufficient"]'::jsonb, 2, 'Systems without forced distribution or differentiation requirements allow rating inflation. While manager training and documentation matter, the root issue is an HR process that permits and incentivizes leniency. The system design must enforce meaningful differentiation.'),
('shrm-scp', 'Acuity', 'An HR leader is analyzing whether to consolidate three HR service centers into one shared services center. What metric BEST validates the decision?', '["Employee satisfaction with HR services; HR team productivity; quality of hiring and onboarding outcomes", "Reduction in HR department operating budget", "Total cost per HR transaction", "Percentage reduction in HR headcount"]'::jsonb, 0, 'While cost reduction is important, shared services success requires balancing efficiency with quality and employee experience. Employee satisfaction, HR productivity, and outcomes (hiring quality, compliance, onboarding effectiveness) must not degrade. Cost-only focus can harm service quality and business outcomes.'),
('shrm-scp', 'Acuity', 'Talent market analysis shows that competitors are offering remote-first arrangements while your company requires three days onsite. How should HR validate whether this policy impacts recruitment?', '["Track offer acceptance rates and reasons for declined offers; compare sourcing and hiring timelines", "Benchmark competitor remote policies", "Conduct a focus group on workplace flexibility", "Survey current employees on remote work preferences"]'::jsonb, 0, 'Actual hiring data (offer acceptance rates, reasons for declines, hiring timeline/difficulty) provides concrete evidence of policy impact on recruitment. Surveys of current employees and focus groups reflect preferences but not actual hiring outcomes. Benchmarking shows peer practices but not impact on your hiring.'),
('shrm-scp', 'Acuity', 'An HR leader observes that contractors represent 22% of the workforce (up from 8% five years ago). What is the MOST important strategic analysis?', '["Comparison of contractor vs. employee hourly rates", "Assessment of core vs. non-core work allocation and contractor dependency risks", "Legal compliance review of contractor classifications", "Trends in contractor market availability"]'::jsonb, 1, 'A significant increase in contractor reliance requires strategic assessment of whether this reflects intended workforce flexibility or uncontrolled contingency growth. Understanding which roles are contingent (and whether they''re core or non-core) informs risk management and workforce strategy.'),
('shrm-scp', 'Acuity', 'A company''s leadership pipeline analysis reveals that only 18% of senior leaders are under age 50, while the general workforce averages 38% under 50. What diagnostic question should be explored?', '["Should external leadership recruitment focus on younger candidates?", "What is the average age of employees hired externally for leadership roles?", "Is age discrimination occurring in promotion decisions?", "Are younger high-potentials being identified and developed, or are internal succession candidates aging in place?"]'::jsonb, 3, 'This pattern could reflect stagnation in the leadership pipeline (high-potentials leaving, internal candidates aging without promotion) rather than bias. Understanding whether young talent is being identified and developed, or departing, guides succession planning and development strategies.'),
('shrm-scp', 'Acuity', 'An HR leader notes that the time-to-fill for engineering roles is 95 days, while other roles average 45 days. Before implementing corrective action, what data would clarify the root cause?', '["Analyze hiring source (referral vs. external), interview-to-offer acceptance rates, and offer negotiation duration", "Benchmark engineering time-to-fill against industry standards", "Increase recruiter focus on engineering to speed up hiring", "Increase sign-on bonuses for engineering roles"]'::jsonb, 0, 'The extended timeline could reflect sourcing challenges (limited referral pipeline), high rejection rates (poor fit or interview process), or extended negotiations (competitive market). Data on source quality, acceptance rates, and negotiation duration points to which stage needs attention.'),
('shrm-scp', 'Acuity', 'An organization implemented a new LMS and engagement metrics show only 32% of employees have completed assigned courses within 30 days of assignment. What is the BEST diagnostic approach?', '["Reduce course length to improve completion rates", "Analyze which employee segments, departments, and course types show lower engagement", "Survey employees on LMS usability", "Make training completions mandatory and monitor compliance"]'::jsonb, 1, 'Segmented analysis (by department, role, course type, demographics) reveals patterns. Lower compliance in certain groups may reflect relevance issues, technical barriers, lack of manager reinforcement, or workload. This diagnosis is essential before mandates or broad solutions.'),
('shrm-scp', 'Acuity', 'A business unit''s revenue per employee is $280K, while the company average is $350K. How should HR partner with the business unit leader to diagnose the issue?', '["Implement performance management changes to increase output", "Benchmark the business unit against similar external competitors", "Request an increase in headcount to boost absolute revenue", "Analyze employee productivity, product mix, pricing, and staffing composition relative to performance"]'::jsonb, 3, 'Revenue per employee reflects both workforce factors (productivity, skill mix, staffing levels) and business factors (product mix, pricing, market demand). HR must collaborate to analyze all contributors—not just blame workforce factors. The diagnostic work informs appropriate solutions.'),
('shrm-scp', 'Acuity', 'Women comprise 45% of the workforce but only 22% of senior management. What analysis should HR lead to understand if this reflects systemic issues or other factors?', '["Analyze representation trends over time, exit rates by gender at each level, and promotion rates; conduct qualitative interviews with high-potential women", "Compare hiring rates of men vs. women at all levels", "Increase recruitment targets for female senior leaders externally", "Review performance ratings to identify gender bias"]'::jsonb, 0, 'Comprehensive analysis includes pipeline representation (are women advancing to senior-level pools?), exit patterns (are women leaving before senior roles?), and promotion rates. Qualitative interviews reveal barriers (bias, culture, development opportunities). This multi-factor approach reveals root causes.'),
('shrm-scp', 'Acuity', 'An organization''s diversity hiring initiative has brought women representation in engineering from 12% to 18% over two years. What is the MOST critical metric to track next?', '["Continue expanding diversity hiring targets to reach 40% by year three", "Assess whether current female engineers are distributed across all technical levels", "Measure engagement scores of female engineers vs. male engineers", "Monitor retention and advancement of newly hired women engineers at 2-year and 5-year marks"]'::jsonb, 3, 'Hiring diverse talent is step one; retention and advancement reveal whether the culture supports diversity. Early departures or stalled advancement of women hired under diversity initiatives indicate systemic barriers. This data guides culture and inclusion interventions.'),
('shrm-scp', 'Acuity', 'A post-training evaluation shows that 87% of participants rate a leadership development program as ''excellent,'' yet subsequent 360-degree feedback shows minimal behavioral change. What is the likely explanation?', '["Participants were not receptive to feedback", "The training was effective but participants did not apply learning on the job", "Reaction evaluations (''excellent rating'') do not validate learning or behavior change; evaluation design should include on-the-job application metrics", "Facilitators were skilled but program content was weak"]'::jsonb, 2, 'This illustrates the Kirkpatrick model limitation: participant satisfaction (Level 1 reaction) does not ensure learning or behavior change (Levels 2-4). Evaluation design must include pre/post knowledge assessments and follow-up behavioral indicators. Redesign should focus on application reinforcement and accountability.'),
('shrm-scp', 'Strategic HR Management', 'A company''s five-year business strategy emphasizes international expansion into emerging markets. What HR capability must be developed to support this strategy?', '["Reduce domestic headcount to fund international initiatives", "Hire international HR staff and delegate strategy execution to them", "Build global talent acquisition, cultural competency, and expatriate management capabilities", "Maintain current HR processes and hire more administrative support"]'::jsonb, 2, 'International expansion requires HR to build specific capabilities: global sourcing, cultural intelligence training, expatriate assignment management, compliance across jurisdictions. These capabilities directly enable the business strategy and cannot be delegated without strategic oversight.'),
('shrm-scp', 'Strategic HR Management', 'A manufacturing company is automating 40% of production roles over the next three years. Which HR strategic initiative should be prioritized?', '["Develop reskilling and career transition programs for affected employees", "Accelerate hiring to offset automation losses", "Implement layoff procedures for displaced employees", "Maintain status quo and manage separations as automation progresses"]'::jsonb, 0, 'Proactive reskilling programs position the company to retain trained talent, reduce separation costs, preserve morale, and maintain workforce stability during transformation. This is more strategic than reactive layoffs and better than hoping hiring will absorb the changes.'),
('shrm-scp', 'Strategic HR Management', 'A retail organization aims to become the ''best place to work in retail'' within five years. What metrics should HR establish to track progress toward this strategic goal?', '["Customer satisfaction and net promoter scores", "Absenteeism and turnover reduction targets; training hours per employee", "Industry ''best employer'' award rankings and Great Place to Work certification scores", "Employee satisfaction scores; retention rates; talent acquisition speed; diversity metrics"]'::jsonb, 3, 'Strategic goals require leading indicators that HR controls: employee satisfaction, retention, recruitment quality, and diversity. While external awards validate success, they lag. Leading indicators (satisfaction, retention, hiring) allow mid-course corrections aligned to the vision.'),
('shrm-scp', 'Strategic HR Management', 'A healthcare organization''s strategic plan emphasizes patient experience and safety. How should HR align talent management to this strategy?', '["Increase compensation across all healthcare roles", "Implement stricter disciplinary policies", "Align hiring criteria, training focus, and performance metrics to patient safety and experience outcomes", "Hire only experienced healthcare workers"]'::jsonb, 2, 'Strategic alignment requires translating business priorities into HR practices. Hiring criteria should assess patient-safety mindset, training should emphasize patient experience, and performance evaluations should reward safety and quality metrics. This creates systemic alignment.'),
('shrm-scp', 'Strategic HR Management', 'A technology company''s strategy includes acquiring three startups over the next 18 months. What HR strategic capability must be strengthened?', '["Develop M&A integration expertise, cultural integration planning, and talent retention processes", "Increase recruitment of experienced external leaders", "Hire integration consultants to manage acquisitions", "Expand training programs before acquisitions occur"]'::jsonb, 0, 'HR must build internal M&A integration capability: pre-acquisition due diligence (cultural fit, key talent risks), integration planning (role harmonization, culture blending), and retention programs. This strategic capability directly impacts acquisition success and integration outcomes.'),
('shrm-scp', 'Strategic HR Management', 'A business unit''s growth strategy depends on increasing sales productivity by 30% without proportional headcount increases. What is HR''s strategic role in enabling this goal?', '["Hire more experienced sales leaders externally", "Reduce compensation to improve profit margins", "Assess sales team capability and opportunity gaps; redesign roles, develop specific skills, and optimize processes and tools", "Implement aggressive performance management to drive output"]'::jsonb, 2, 'Productivity goals require HR to diagnose capability gaps (training, skills), organizational design (role clarity, incentives), and environmental factors (tools, processes). HR partners with operations to identify and eliminate barriers to higher productivity.'),
('shrm-scp', 'Strategic HR Management', 'A financial services firm plans to expand into private wealth management, a business segment requiring high client relationship skills and trust. What HR strategic initiative aligns with this expansion?', '["Develop leadership competency models emphasizing relationship building; create pathways for high-potential bankers to transition into wealth management", "Outsource private wealth management to specialized firms", "Maintain existing talent strategies and hire incrementally", "Recruit wealth managers externally at premium compensation"]'::jsonb, 0, 'Strategic expansion requires HR to develop competency models for the new business, identify and develop internal talent with relationship-building potential, and create career pathways. This retains talent while building capability aligned to new business demands.'),
('shrm-scp', 'Strategic HR Management', 'A manufacturing company''s strategy includes operating with a 30% smaller workforce through automation and process optimization. Which HR strategic decision supports this?', '["Begin aggressive recruitment to build redundancy", "Conduct immediate layoffs to reach the target workforce size", "Freeze hiring and allow natural attrition", "Implement a strategic reskilling program and voluntary separation plan; optimize workforce to higher-value roles"]'::jsonb, 3, 'Strategic downsizing requires proactive, planned approaches: reskilling retains capable employees for higher-value roles, voluntary separations reduce forced layoffs, and phased transitions maintain operations. This is more controlled than reactive layoffs or passive freezes.'),
('shrm-scp', 'Strategic HR Management', 'A company''s business strategy emphasizes data-driven decision-making and analytics across all functions. What HR strategic transformation is required?', '["Maintain current HR processes and request ad-hoc reports from IT", "Outsource HR analytics to a consulting firm", "Build analytics capability in HR; establish data governance; invest in HRIS and reporting; develop HR team analytics skills", "Add more HR staff to generate reports"]'::jsonb, 2, 'Strategic alignment requires HR to build internal analytics capability: modernized systems, data governance, skilled analysts, and self-service reporting. This positions HR to support business analytics culture while providing people insights.'),
('shrm-scp', 'Strategic HR Management', 'A consulting firm''s strategic focus is shifting from project-based work to retainer-based client relationships requiring long-term team continuity. How should HR strategy adapt?', '["Shift to higher-contract worker usage for flexibility", "Expand executive recruitment to bring in relationship-focused leaders", "Develop retention programs, career stability messaging, and team-based incentives; reduce involuntary separations", "Increase performance management rigor to motivate retention"]'::jsonb, 2, 'Retainer models require stable, relationship-focused teams. HR strategy must emphasize retention (career paths, stability), team cohesion (incentives), and messaging around long-term engagement. This contrasts with project-based strategies that favor flexibility.'),
('shrm-scp', 'Strategic HR Management', 'A CEO''s strategic imperative is to improve company culture and reduce voluntary turnover by 25% over two years. What stakeholder must HR engage most closely to develop this strategy?', '["Executive leadership to approve HR budget increases", "External consulting firms to design culture transformation", "Operations and business unit leaders to identify culture barriers and align management practices", "Employees through surveys to understand their preferences"]'::jsonb, 2, 'Culture is shaped by manager behavior, business practices, and operational decisions—not HR programs alone. HR must partner with operations and business leaders to align hiring criteria, management practices, role design, and accountability to culture goals.'),
('shrm-scp', 'Strategic HR Management', 'A nonprofit''s strategic plan focuses on expanding service capacity in underserved communities. What HR strategic capability must be developed?', '["Build community engagement and cultural competency; develop partnerships with community organizations; ensure programs reflect community needs", "Hire experienced nonprofit executives from larger organizations", "Increase CEO and board compensation to attract more experienced leaders", "Implement training programs for all staff on the nonprofit''s services"]'::jsonb, 0, 'Expansion into underserved communities requires cultural competency and community trust. HR must develop hiring practices emphasizing community connection, training on cultural responsiveness, and partnerships with community stakeholders. External hires alone cannot build community credibility.'),
('shrm-scp', 'Strategic HR Management', 'A company plans to pivot from product sales to a subscription model requiring different sales skills and customer mindsets. What is HR''s strategic role in this transition?', '["Recruit entirely new sales team with subscription experience", "Maintain existing sales team and provide basic subscription training", "Hire subscription sales leadership externally and let them build their team", "Develop competency models for subscription selling; assess current sales team capability; create training and transition plans for those who can adapt"]'::jsonb, 3, 'Strategic business transitions require HR to assess which current talent can adapt (retention of institutional knowledge), develop new competencies, and create career pathways. This balances change with retention of capable people and minimizes disruption.'),
('shrm-scp', 'Strategic HR Management', 'A bank''s digital transformation strategy requires embedding technology literacy across all roles. How should HR approach this capability development?', '["Hire a Chief Digital Officer and delegate transformation to them", "Require all employees to attend a one-time technology training course", "Assess technology capability gaps by role; design targeted development; provide tools, practice time, and support; recognize adoption milestones", "Hire tech-savvy younger employees to replace current staff"]'::jsonb, 2, 'Capability development requires assessment, targeted design, environmental support (tools, time, practice), and reinforcement. One-time training without follow-up support and role redesign typically fails. HR must embed digital thinking into hiring, development, and performance expectations.'),
('shrm-scp', 'Strategic HR Management', 'A company''s strategic goal is to increase innovation and speed-to-market. What HR practice most directly supports this?', '["Increase R&D budget allocation", "Implement mandatory innovation training", "Align hiring criteria, psychological safety messaging, experimentation rewards, and failure tolerance into culture and performance management", "Create a separate innovation team"]'::jsonb, 2, 'Innovation requires psychological safety, tolerance for failure, and accountability for experimentation. HR shapes this through hiring (selecting for creativity, risk tolerance), management training (coaching for psychological safety), and performance evaluation (rewarding experimentation, not penalizing failures).'),
('shrm-scp', 'Strategic HR Management', 'A company acquires a competitor with a distinct culture and 30% higher turnover. What is the HR leader''s strategic priority in the first 100 days post-acquisition?', '["Implement the acquiring company''s HR policies immediately across the acquired company", "Retain key talent; diagnose culture integration opportunities; communicate vision and uncertainty reduction; preserve what works while introducing needed changes", "Evaluate all acquired company leadership for fit with acquiring company", "Conduct organizational redesign to eliminate redundancy"]'::jsonb, 1, 'Early post-acquisition priorities are retention of key talent and diagnosis of what''s working vs. what needs change. Premature standardization risks losing talent. Strategic HR ensures communication, addresses uncertainty, and makes deliberate integration decisions.'),
('shrm-scp', 'Strategic HR Management', 'A retailer''s strategy includes expanding e-commerce from 18% to 40% of revenue within three years. What HR strategic partnership is essential?', '["Store operations to maintain physical retail productivity", "Finance to ensure adequate compensation budgets", "Customers to gather insights on digital preferences", "IT and marketing to understand e-commerce skill and staffing requirements; align hiring, development, and organizational design"]'::jsonb, 3, 'E-commerce expansion requires different skills (digital marketing, analytics, user experience, online customer service). HR must partner with IT and marketing to identify skill gaps, plan hiring/development, and redesign organization to support growth.'),
('shrm-scp', 'Strategic HR Management', 'A nonprofit''s strategic plan includes increasing program effectiveness and reducing overhead. How should HR contribute?', '["Outsource HR functions to reduce overhead", "Reduce employee benefits to save costs", "Align talent strategy to program outcomes; invest in frontline staff development; measure program effectiveness by outcomes, not activities", "Reduce HR staff to lower overhead"]'::jsonb, 2, 'Nonprofit effectiveness depends on frontline staff capability and program design. HR''s strategic role is aligning talent to mission outcomes, developing frontline staff, and measuring impact. This improves effectiveness while respecting mission-driven culture.'),
('shrm-scp', 'Strategic HR Management', 'A manufacturing company''s digital transformation includes implementing AI-driven predictive maintenance. What HR strategic initiative supports this capital investment?', '["Automate maintenance roles entirely through AI", "Hire AI specialists externally", "Develop internal AI literacy; create roles for AI implementation; train maintenance technicians on AI insights; redesign roles to leverage AI recommendations", "Hire consultants to implement and operate the AI system"]'::jsonb, 2, 'Technology investments succeed when workforce is prepared and roles are redesigned. HR must develop AI literacy, create new roles (AI implementation, oversight), and retrain technicians to interpret and act on AI insights. This maximizes technology value while retaining capable people.'),
('shrm-scp', 'Strategic HR Management', 'A company''s strategic emphasis on sustainability requires embedding environmental responsibility into operations. What HR strategic practice supports this?', '["Align hiring criteria, training content, performance metrics, and leadership development to sustainability values; embed sustainability into performance expectations", "Hire sustainability consultants to manage environmental initiatives", "Create a sustainability committee separate from operations", "Provide optional sustainability training"]'::jsonb, 0, 'Strategic values become cultural reality through HR systems: hiring (selecting for sustainability mindset), development (embedding sustainability thinking), and performance management (holding leaders accountable for sustainability outcomes). Optional training alone does not drive culture change.'),
('shrm-scp', 'Strategic HR Management', 'A healthcare system plans to establish a new urgent care network requiring rapid staff hiring and training. What HR strategic capability must be built?', '["Increase recruitment advertising spend", "Delay expansion until traditional recruitment processes fill roles", "Develop scalable onboarding and training programs; build network relationships with regional talent pools; establish rapid credentialing processes", "Hire experienced urgent care administrators to build the network"]'::jsonb, 2, 'Rapid expansion requires scalable, efficient HR processes: streamlined onboarding, trained talent networks, expedited credentialing. These capabilities enable growth pace while maintaining quality and compliance. They represent strategic HR capability, not just recruiting.'),
('shrm-scp', 'Strategic HR Management', 'A company''s CEO has declared a strategic focus on improving margins through operational efficiency. What HR metric should be tracked to align with this goal?', '["Recruitment speed and quality of hires", "Employee turnover and engagement scores", "Headcount and labor cost as percentage of revenue; productivity metrics; process efficiency improvements", "Training spending per employee"]'::jsonb, 2, 'Operational efficiency goals require HR to track labor economics (cost per unit of work) and productivity. Headcount optimization, labor cost management, and process improvements directly support margin goals. General metrics (turnover, engagement) are important but less directly aligned.'),
('shrm-scp', 'Strategic HR Management', 'A financial services firm''s strategy includes expanding into emerging markets where talent is scarce but compensation expectations are rising. What HR strategic decision must be made?', '["Delay expansion until local talent supply increases", "Develop tiered compensation strategies by market; invest in local talent development; build expatriate support; align global total rewards strategy", "Hire primarily experienced expat leaders from headquarters", "Minimize compensation to maintain margin targets"]'::jsonb, 1, 'Emerging market expansion requires sophisticated talent strategy: market-based compensation, local talent development, cultural adaptation, and expat support. One-size-fits-all compensation fails, as does relying on expats. Strategic flexibility is essential.'),
('shrm-scp', 'Strategic HR Management', 'A manufacturing company''s strategic goal is to achieve operational excellence. What HR capability is foundational to this goal?', '["Develop frontline team capabilities and problem-solving mindsets; implement continuous improvement training; measure team engagement in improvement initiatives", "Hire lean/Six Sigma experts externally", "Reduce labor costs aggressively", "Implement stricter performance management"]'::jsonb, 0, 'Operational excellence depends on engaged, capable frontline teams identifying and solving problems. HR''s role is developing problem-solving capability, continuous improvement mindsets, and engagement in improvement initiatives. External experts set direction; internal capabilities sustain improvement.'),
('shrm-scp', 'Strategic HR Management', 'A company plans to shift from a centralized organizational model to decentralized, autonomous business units. What HR strategic change is essential?', '["Hire regional HR directors for each unit", "Redesign HR service delivery model (central governance, local operations); develop accountability frameworks; shift manager responsibilities for talent decisions", "Maintain centralized HR and have business units request HR support", "Increase HR staff to support more distributed units"]'::jsonb, 1, 'Organizational decentralization requires HR to shift from centralized control to distributed accountability. Service delivery becomes hybrid (central governance for policy, local execution), and managers gain more talent decision authority. This requires redesigning HR''s model and manager capabilities.'),
('shrm-scp', 'HR Expertise', 'An organization is restructuring from a functional to a matrix structure. What HR expertise is required to design roles and accountability in a matrix environment?', '["Define clear role accountabilities, decision rights, and escalation processes; establish role clarity frameworks to prevent confusion", "Implement strict hierarchical approvals to prevent conflicts", "Hire matrix management consultants to build the organization", "Increase hiring to fill matrix role duplications"]'::jsonb, 0, 'Matrix structures create ambiguity without clear role definition and decision-making frameworks. HR expertise includes defining what each role accountable for (resource allocation, technical decisions, people decisions), preventing the conflicts that derail matrix organizations.'),
('shrm-scp', 'HR Expertise', 'A manager has received 360-degree feedback indicating low collaboration skills. What is HR''s coaching approach to develop this capability?', '["Recommend the manager take a collaboration course", "Conduct discovery of collaboration barriers; design targeted coaching with specific behavioral targets; establish accountability and measurement; provide follow-up support", "Document the feedback as a performance issue", "Move the manager to a role requiring less collaboration"]'::jsonb, 1, 'Behavioral change requires HR expertise in coaching design: diagnosis (identifying barriers—communication style, beliefs, lack of skills), targeted interventions (specific behaviors to change), accountability, and reinforcement. Generic training alone typically fails.'),
('shrm-scp', 'HR Expertise', 'An organization''s leadership bench is weak for critical roles. What succession planning approach should HR recommend?', '["Hire all critical roles externally", "Do nothing and address succession when vacancies occur", "Promote the most senior person regardless of readiness", "Conduct systematic capability assessment; develop high-potential candidates; create accelerated development paths; establish readiness criteria and timelines"]'::jsonb, 3, 'Robust succession planning requires systematic HR expertise: identifying high-potential talent, assessing capability gaps, designing targeted development, and establishing readiness criteria. This develops internal talent while managing continuity risk.'),
('shrm-scp', 'HR Expertise', 'An HR leader discovers that two departments have very different pay practices for similar roles. How should this be addressed?', '["Allow departments to maintain autonomy in pay decisions", "Implement strict job evaluation to eliminate flexibility", "Conduct pay equity analysis; identify market and role-based justifications; establish aligned pay structures; address inequities systematically", "Immediately harmonize all pay to the higher level"]'::jsonb, 2, 'Pay consistency requires HR expertise in analysis: understanding market rates for roles, assessing internal equity, identifying legitimate differences (market, role complexity), and addressing true inequities. This balances consistency with market competitiveness and justifiable differences.'),
('shrm-scp', 'HR Expertise', 'A company wants to implement performance-based pay. What HR expertise is essential to ensure success?', '["Implement individual bonuses based on manager discretion", "Replace all base salary with performance pay", "Distribute a portion of base salary based on performance ratings", "Design clear performance metrics; establish fair assessment processes; communicate pay-to-performance linkage; train managers on objective evaluation; monitor equity"]'::jsonb, 3, 'Performance-based pay requires HR expertise in metric design (clear, measurable, controllable), assessment rigor (training managers, reducing bias), communication (transparency), and monitoring (ensuring equity and effectiveness). Poorly designed systems create demotivation.'),
('shrm-scp', 'HR Expertise', 'An organization is implementing a new HRIS. What HR expertise is needed to ensure effective adoption and data quality?', '["Requirements gathering; change management planning; user training and support; data migration verification; governance and system ownership", "Hire a consultant to implement and train", "Use a basic system and add manual tracking as needed", "IT should select the system and HR should use it"]'::jsonb, 0, 'HRIS success requires HR expertise in defining requirements (workflows, data needs), managing change (user adoption, resistance), ensuring data quality, and establishing governance. HR''s business knowledge is essential—IT selects technology but HR ensures fit and adoption.'),
('shrm-scp', 'HR Expertise', 'A company wants to develop a strong employer brand. What HR expertise should lead this initiative?', '["Outsource employer branding to a recruitment firm", "Marketing team should define the employer brand", "Focus only on recruiting, not on brand building", "HR leads brand definition by conducting employee research, articulating value proposition, defining candidate experience, and coordinating messaging across recruiting and retention"]'::jsonb, 3, 'Employer brand stems from actual employee experience and organizational value proposition. HR expertise includes understanding culture, conducting employee research, defining what makes the organization attractive, and aligning candidate experience to messaging. HR and marketing partner, but HR leads the substance.'),
('shrm-scp', 'HR Expertise', 'An organization is designing a competency model for leadership. What should HR include to ensure the model drives organizational outcomes?', '["Use competencies only for hiring, not development", "Define competencies aligned to business strategy; include behavioral indicators; establish assessment methods; link to development and promotion; cascade to lower levels", "Create a single global competency model for all roles", "List generic leadership competencies from industry models"]'::jsonb, 1, 'Effective competency models require HR expertise in alignment (linking to strategy), specificity (behavioral indicators, not vague traits), assessment rigor, and integration into talent systems. Models without these elements become desk-drawer documents.'),
('shrm-scp', 'HR Expertise', 'An HR leader is designing a talent review process for succession planning. What elements are essential to identify high-potential employees accurately?', '["Select only employees who have been with the company longest", "Identify high-potentials based on manager nominations without verification", "Base identification solely on current performance ratings", "Assess current performance, learning ability, readiness for next level, and potential for advancement; include diverse evaluator perspectives; use multiple data sources"]'::jsonb, 3, 'Accurate high-potential identification requires HR expertise in assessing readiness (not just past performance), potential (learning ability, ambition, capability for growth), and process rigor (multiple evaluators, data sources) to reduce bias and improve accuracy.'),
('shrm-scp', 'HR Expertise', 'A company is establishing a performance management system. What competency must HR demonstrate to design one that actually improves performance?', '["Establish clear goals aligned to strategy; create feedback frequency and coaching relationships; differentiate performance; link to development and rewards", "Design a rating scale and require annual reviews", "Use the system primarily to document poor performers for termination", "Implement a ranking system to force differentiation"]'::jsonb, 0, 'Effective performance management requires HR expertise in goal alignment, feedback mechanisms (continuous, not annual only), coaching, differentiation, and integration with development and rewards. Poor-performing systems become compliance exercises rather than performance drivers.'),
('shrm-scp', 'HR Expertise', 'An organization discovers that interview assessments have low predictive validity for job performance. What HR expertise is needed to improve hiring accuracy?', '["Conduct job analysis to understand success factors; develop structured interview questions; add work samples or assessments; validate assessments against performance data", "Increase interview time to gather more information", "Use more candidates and hire the best interviewed candidate", "Hire external recruiters to improve interviewer quality"]'::jsonb, 0, 'Improving hiring accuracy requires HR expertise in understanding what predicts job success (job analysis), structured assessment (questions, work samples), and validation (does the assessment predict performance?). Unstructured interviews and more time do not improve prediction.'),
('shrm-scp', 'HR Expertise', 'An organization is designing a management training program to improve team leadership. What should HR do to ensure training transfers to the job?', '["Provide optional training and encourage participation", "Send managers to an external leadership academy", "Deliver high-quality content and assume participants will apply learning", "Assess current capability gaps; design training aligned to gaps; establish pre-training and post-training accountability; provide manager coaching; measure on-the-job application"]'::jsonb, 3, 'Training transfer requires HR expertise in diagnosis (what gaps exist?), design (aligned to needs), accountability (pre/post measures, manager responsibility), and follow-up (coaching, not one-time event). Training content alone does not create behavior change.'),
('shrm-scp', 'HR Expertise', 'A company is expanding internationally and needs to establish compensation practices. What HR expertise must guide localization decisions?', '["Minimize compensation globally to improve margins", "Let each country''s HR leader set compensation independently", "Conduct market analysis by location; understand local practices and tax implications; develop localized total rewards strategies; maintain some global equity controls", "Use the same compensation structure globally"]'::jsonb, 2, 'Global compensation requires HR expertise in market analysis (local pay rates), regulatory knowledge (tax, compliance), competitiveness, and maintaining some equity controls (pay ratios across locations). Blanket globalization or extreme localization both create problems.'),
('shrm-scp', 'HR Expertise', 'An HR leader is designing a benefits program. What expertise is needed to balance cost and employee value?', '["Offer low-cost benefits to minimize company expense", "Conduct employee needs assessment; analyze utilization and satisfaction; design programs addressing high-priority needs; communicate value clearly; monitor cost and utilization trends", "Copy competitor benefits packages", "Offer comprehensive benefits without regard to cost"]'::jsonb, 1, 'Benefits design requires HR expertise in understanding employee needs (varies by demographics), analyzing cost-effectiveness, communication (employees often undervalue benefits), and ongoing monitoring. Needs-based design optimizes both cost and employee satisfaction.'),
('shrm-scp', 'HR Expertise', 'A company wants to implement a mentoring program. What HR expertise ensures the program creates real development impact?', '["Mandate mentoring for all employees", "Pair mentors and mentees and let them self-direct", "Implement mentoring only for high-potential employees", "Establish clear program goals; provide mentor and mentee training; establish meeting structures and learning goals; monitor progress; measure impact on development and retention"]'::jsonb, 3, 'Effective mentoring programs require HR expertise in structure (not just pairing), training (what makes effective mentoring?), goal-setting, and measurement (does mentoring improve development outcomes?). Unstructured programs often fail due to lack of clarity and accountability.'),
('shrm-scp', 'HR Expertise', 'An organization is designing a compliance training program. What approach ensures knowledge retention and behavior change?', '["Require employees to pass a test and be done", "Assess knowledge gaps; design targeted micro-learning; establish accountability for managers and employees; measure knowledge and behavior; reinforce regularly", "Deliver compliance training annually and document completion", "Use an online compliance course vendor without customization"]'::jsonb, 1, 'Compliance training requires HR expertise in assessment (where are gaps?), design (targeted, not generic), reinforcement (not one-time), and measurement (do employees demonstrate compliant behavior?). Annual theater compliance does not prevent violations.'),
('shrm-scp', 'HR Expertise', 'A manager has indicated they want to terminate a struggling employee. What should HR do before proceeding?', '["Escalate to general counsel immediately", "Require the employee to resign", "Authorize the termination based on the manager''s assessment", "Conduct a performance improvement assessment; ensure documentation and legal compliance; explore alternatives; conduct a final conversation with the employee"]'::jsonb, 3, 'Termination requires HR expertise in fair process (documentation, alternatives explored), legal compliance (avoiding discrimination claims), and procedure (final conversation, severance). Hasty terminations create litigation risk and reputational damage.'),
('shrm-scp', 'HR Expertise', 'An organization is experiencing high absenteeism and wants to implement stricter absence policies. What HR expertise should guide this decision?', '["Implement disciplinary policy for absences immediately", "Terminate employees with high absence rates", "Create a point-based system with automatic termination", "Analyze absence patterns and root causes; address underlying health, engagement, or management issues; design supportive policies; consider disciplinary measures only for patterns indicating abuse"]'::jsonb, 3, 'Absenteeism requires HR expertise in diagnosis (is it medical, disengagement, management issue?). Penalties without understanding cause often fail and create legal risks. HR should balance support (accommodations for medical, engagement improvements) with appropriate discipline.'),
('shrm-scp', 'HR Expertise', 'An organization wants to eliminate its annual performance review and shift to continuous feedback. What HR expertise is required for the transition?', '["Eliminate all performance feedback", "Design feedback frameworks and manager training; establish frequency expectations and accountability; clarify how feedback informs development and decisions; monitor implementation", "Continue annual reviews while adding ad-hoc feedback", "Tell managers to stop conducting reviews and provide feedback whenever"]'::jsonb, 1, 'Shifting feedback models requires HR expertise in implementation design (frameworks, manager training), not just elimination of old systems. Without structure, continuous feedback often becomes either absent or unfocused criticism. HR establishes expectations and accountability.'),
('shrm-scp', 'HR Expertise', 'An organization is designing promotion criteria to improve fairness and transparency. What should be included?', '["Use tenure as the primary promotion factor", "Base promotion decisions solely on manager recommendation", "Allow each manager to set their own promotion standards", "Establish clear role requirements; define competency expectations for next level; assess readiness through multiple data sources; create transparency in decision criteria and process"]'::jsonb, 3, 'Transparent promotion processes require HR expertise in defining clear criteria (role requirements, competencies), assessing against criteria rigorously, and communicating the process. Consistency across managers reduces bias and improves fairness.'),
('shrm-scp', 'HR Expertise', 'A company is implementing a workplace flexibility policy (remote, flexible hours). What HR expertise ensures equitable application?', '["Restrict flexibility to executive levels only", "Define eligibility criteria based on role and business needs; establish approval processes; monitor equity across departments and demographics; address manager concerns", "Allow unlimited flexibility for all employees", "Implement without formal policy and handle exceptions ad-hoc"]'::jsonb, 1, 'Flexibility policies require HR expertise in defining criteria (which roles support flexibility?), process (fair approval), and monitoring (ensuring equitable access across groups). Without structure, flexibility becomes inconsistently applied and creates morale issues.'),
('shrm-scp', 'HR Expertise', 'An organization is conducting a compensation study to benchmark pay. What HR expertise ensures accurate results?', '["Use published salary survey data without customization", "Use a single pay consultant''s recommendations", "Select appropriate benchmarking sources; match jobs accurately; consider pay mix and total rewards; analyze market ranges; account for organization size and location", "Conduct informal conversations with peers about pay"]'::jsonb, 2, 'Accurate benchmarking requires HR expertise in selecting appropriate comparables (industry, location, size), matching jobs carefully (title doesn''t indicate level), and understanding market ranges. Poor benchmarking leads to uncompetitive pay and poor decisions.'),
('shrm-scp', 'HR Expertise', 'A company is designing an employee engagement survey. What HR expertise ensures useful results?', '["Use generic survey questions from another organization", "Conduct survey and don''t communicate results or take action", "Define clear survey goals; design targeted questions; select appropriate population and method; analyze results by segments; develop action plans; communicate findings and outcomes", "Create a lengthy survey covering all possible topics"]'::jsonb, 2, 'Effective engagement surveys require HR expertise in design (focused on actionable topics), rigor (valid questions), analysis (segmentation reveals patterns), and follow-through (communicating results and taking action). Poorly designed surveys create cynicism about HR listening.'),
('shrm-scp', 'HR Expertise', 'An HR leader is establishing a recognition and rewards program. What should be included to drive desired behaviors?', '["Define behaviors aligned to strategy; establish recognition mechanisms (formal and informal); ensure fairness and equity; communicate program clearly; measure participation and impact", "Provide monetary bonuses based on manager discretion", "Implement program without clear criteria", "Focus only on financial rewards"]'::jsonb, 0, 'Recognition programs require HR expertise in aligning to strategy, establishing clear criteria (which behaviors are recognized?), ensuring equitable access, and measuring impact. Discretionary bonuses without criteria create favoritism and misalignment.'),
('shrm-scp', 'HR Expertise', 'A company wants to build a talent pipeline for critical technical skills. What HR expertise is needed?', '["Conduct skills gap analysis; develop internal talent through technical training; build recruitment pipelines with universities and bootcamps; create career pathways; establish mentoring", "Hire contractors for all specialized roles", "Wait for candidates to apply organically", "Recruit experienced technical experts externally only"]'::jsonb, 0, 'Building technical talent pipelines requires HR expertise in forecasting (future skill needs), development (training paths), and sourcing (universities, bootcamps). Relying solely on external recruitment is expensive and risky for critical skills.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit leader asks HR why the customer-facing team has high turnover. What is the BEST consulting question HR should ask first?', '["Have you considered increasing compensation?", "Should we implement retention bonuses?", "Have you considered outsourcing customer service?", "What outcomes are you trying to achieve? What would lower turnover improve—service quality, cost, relationships?"]'::jsonb, 3, 'Effective HR consultation begins with understanding business outcomes, not jumping to solutions. Understanding what the business is trying to achieve clarifies whether turnover is a problem (some turnover may be healthy) or masks other issues. This shows business acumen.'),
('shrm-scp', 'Consultation & Business Acumen', 'A CFO expresses concern that HR headcount has grown 40% while business revenue is flat. How should the HR leader respond?', '["Conduct analysis of HR value delivered; demonstrate what capabilities were added; assess whether HR services are meeting business needs; propose changes if efficiency is needed", "Explain that HR is important and headcount growth is justified", "Request increased HR budget to continue growth", "Propose outsourcing HR functions to reduce costs"]'::jsonb, 0, 'This requires HR business acumen: understanding finance concerns, demonstrating value (not defending growth), and proposing solutions that balance costs with services. HR must speak the business language of value and efficiency.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is invited to the strategic planning meeting for the first time. What should HR''s role be in this meeting?', '["Understand business strategy and identify talent implications; raise capability gaps and risks; propose HR initiatives aligned to strategy", "Ask about timeline for implementing HR programs", "Request budget and headcount for HR initiatives", "Listen and report back to HR team about upcoming business changes"]'::jsonb, 0, 'Strategic HR leadership requires translating business strategy into talent implications. HR should identify what capability, culture, organization design, and talent management changes the strategy requires. This consultative role adds business value.'),
('shrm-scp', 'Consultation & Business Acumen', 'An operational leader proposes a 30% headcount reduction to improve margins. How should the HR leader approach this consultation?', '["Analyze implications (which roles, capability impact, customer impact, talent retention risk); propose alternatives; model financial and operational impact", "Propose reducing compensation instead", "Challenge whether the reduction is necessary without understanding alternatives", "Agree to the reduction and begin layoff planning"]'::jsonb, 0, 'Business consultation requires HR to understand financial goals but propose solutions considering talent implications. Analysis might show that modest reductions in specific roles, combined with process improvements, achieve margin goals with less disruption. HR brings talent perspective to business decisions.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit is struggling with execution on a new product launch. The general manager blames the marketing team. As an HR consultant, what question would reveal the MOST important context?', '["Should we replace the marketing leader?", "Is the marketing team fully staffed and experienced?", "What execution challenges are occurring, and do talent, capability, or organizational alignment issues contribute?", "Are marketing compensation levels competitive?"]'::jsonb, 2, 'Before blaming teams or proposing solutions, HR consultants should diagnose root causes: Is execution failing due to capability gaps? Unclear accountability? Interdepartmental alignment? Tools and resources? This systemic thinking demonstrates business acumen beyond HR-only solutions.'),
('shrm-scp', 'Consultation & Business Acumen', 'A CEO asks HR to help improve operational efficiency and cost management. What is the FIRST step in this consulting engagement?', '["Propose implementing new performance management or incentive systems", "Reduce HR spending to model cost discipline", "Understand what ''operational efficiency'' means in this context; identify priority areas; partner with operations leaders to diagnose current-state; identify improvement opportunities", "Immediately propose cost-cutting HR initiatives"]'::jsonb, 2, 'Business acumen requires diagnosis before solutions. Understanding what the CEO means by efficiency (speed, cost, quality, compliance?), identifying priority areas (where are biggest improvements possible?), and partnering with operations ensures HR solutions align with business needs.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is asked to help a struggling business unit improve performance. What data should HR request to inform the consultation?', '["Financial performance, operational metrics (quality, speed, cost), market context, and talent/capability assessment", "Turnover and absenteeism statistics", "Employee satisfaction survey results", "Compensation benchmarking data"]'::jsonb, 0, 'Effective consulting requires understanding the business context: financial performance (what are the targets?), operational metrics (where are gaps?), and talent/capability (are people equipped to execute?). HR data alone (satisfaction, turnover) doesn''t diagnose business problems.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit leader complains that the team lacks ''accountability'' and asks HR for help. What is the MOST consulting-oriented response?', '["Understand what accountability means (clear goals, consequences, execution rigor?); assess current state (goals clear? feedback clear? consequences consistent?); partner to improve specificity", "Implement stricter performance management and discipline", "Create an ''accountability committee''", "Hire more supervisory staff"]'::jsonb, 0, '''Accountability'' is often a symptom descriptor, not a root cause. HR consulting requires digging deeper: Are goals clear? Is feedback timely? Are consequences consistent? Diagnosis reveals whether the issue is clarity, manager capability, or system design—each requiring different solutions.'),
('shrm-scp', 'Consultation & Business Acumen', 'HR is asked to help a retail business improve customer satisfaction scores, which have declined 8 points year-over-year. How should HR approach this consulting engagement?', '["Recommend hiring more experienced customer service staff", "Propose customer service training for frontline employees", "Understand the business context (what changed? competitor activity? product changes?); assess capability (are frontline staff equipped? trained? supported?); identify HR levers", "Propose customer satisfaction incentives"]'::jsonb, 2, 'HR consulting requires business context. An 8-point decline could reflect new competition, product issues, operational problems, or capability gaps. Understanding the business context reveals whether HR should focus on selection, training, capability, incentives, or something else entirely.'),
('shrm-scp', 'Consultation & Business Acumen', 'A CEO is considering a major reorganization. What is the HR leader''s strategic consulting role?', '["Recommend delaying the reorganization", "Execute the reorganization quickly with minimal disruption", "Understand reorganization rationale and expected outcomes; assess talent and capability implications; identify risks (key talent loss, capability gaps); propose phasing and transition support", "Focus on communication planning without challenging strategy"]'::jsonb, 2, 'Strategic HR consulting means understanding the business case while raising talent-related risks and implications. HR should identify which key talent might be at risk, where capability gaps might emerge, and propose transition approaches that minimize disruption while achieving business goals.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit''s product quality metrics are declining. Engineering leadership blames insufficient testing. HR is asked for perspective. What should HR analyze?', '["Accept engineering''s assessment and hire more QA staff", "Understand the issue context (market demand? resource constraints? priorities?); assess whether testing capability is insufficient or whether trade-offs are being made between speed and quality", "Recommend hiring more quality assurance staff", "Propose incentives for quality improvements"]'::jsonb, 1, 'HR business acumen includes understanding operational challenges beyond surface diagnoses. Quality might be declining due to unrealistic timelines, capability gaps, competing priorities, or insufficient resources. HR should partner to understand root causes before proposing solutions.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is advising on whether to build a new capability internally or contract with external vendors. What factors should inform this decision?', '["Choose the lowest-cost option", "Assess strategic importance (is this core to competitive advantage?); consider build vs. buy economics; evaluate vendor availability and reliability; consider risk and control factors", "Always build internally to maintain control", "Always contract externally to minimize headcount"]'::jsonb, 1, 'Build-vs.-buy decisions require business acumen: strategic importance (core or non-core?), financial analysis (total cost of ownership), capability (can we build it?), and risk (vendor dependence?). HR should contribute this analysis, not make decisions by cost alone.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit leader asks HR to help with team conflict that''s affecting productivity. What is the FIRST consulting question?', '["Recommend mediation immediately", "What specific behaviors or issues are driving conflict? What is the business impact? Who is affected beyond these two individuals?", "Should we replace one of the conflicting team members?", "Propose team-building activities to improve relationships"]'::jsonb, 1, 'HR consulting requires diagnosis before solutions. Understanding what the conflict is (interpersonal? disagreement on priorities? unclear accountability?), who''s affected, and what impact it''s having reveals whether the issue needs mediation, clarification of roles, better communication, or structural change.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is consulted on talent strategy for a business unit that''s underperforming financially. What business acumen should guide the recommendation?', '["Propose reducing headcount proportionally", "Understand financial targets and improvement timeline; assess capability and skill gaps; identify whether investment in talent development is needed to drive performance", "Focus only on compensation reductions", "Immediately cut talent costs"]'::jsonb, 1, 'Business acumen means connecting talent decisions to financial outcomes. Underperformance might require investment (capability development, new hires) to drive revenue, not just cost cutting. HR should analyze the business opportunity and propose aligned talent strategies.'),
('shrm-scp', 'Consultation & Business Acumen', 'A company is experiencing rapid growth and needs to scale operations quickly. What is HR''s business-focused consulting contribution?', '["Delay hiring until structure is clear", "Recruit aggressively to fill all open positions", "Outsource functions to reduce headcount and cost", "Assess growth trajectory and capability requirements; identify critical roles and sourcing challenges; recommend staffing and development strategy to support growth without compromising culture"]'::jsonb, 3, 'Growth consulting requires HR to partner with business leadership: understanding growth targets, identifying capability gaps early, planning sourcing (external vs. promotion), and ensuring culture and capability support the growth trajectory. This is strategic HR partnership.'),
('shrm-scp', 'Consultation & Business Acumen', 'A manufacturing facility''s supervisor recommends replacing a high-seniority employee due to declining performance. As an HR consultant, what should you investigate?', '["Support the replacement based on supervisor recommendation", "Assess what''s driving performance decline (health issue? capability gap? changed role? motivation?); explore whether development or accommodation is possible; ensure approach aligns with law and policy", "Facilitate immediate termination", "Recommend reassigning the employee to another department"]'::jsonb, 1, 'HR consulting requires understanding whether replacement is the right solution or whether alternatives exist. Performance decline could reflect changed role, health issues, or coaching gaps—each requiring different approaches. HR should diagnose before agreeing to termination.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is advising on expansion into a new market (geographic or product). What talent and organizational considerations should HR raise?', '["Propose opening the new market without adding headcount", "Assess talent availability and costs; identify required capabilities and development needs; propose market-entry talent strategy; flag cultural and organizational design implications", "Recommend hiring experienced leaders from competitors in that market", "Recommend outsourcing the new venture"]'::jsonb, 1, 'Expansion consulting requires HR to identify talent implications: Is talent available? What capabilities are needed? What will it cost? HR should partner in market-entry strategy, not just execute hiring after decisions are made.'),
('shrm-scp', 'Consultation & Business Acumen', 'A CEO is frustrated that a new strategic initiative is not progressing despite clear communication. HR is asked to assess what''s missing. What is the MOST business-focused approach?', '["Recommend additional training on the initiative", "Propose incentives tied to initiative progress", "Assess whether roles and accountability for the initiative are clear; evaluate whether people have resources and capability; identify barriers (competing priorities, unclear consequences, misalignment)", "Conduct another communication campaign"]'::jsonb, 2, 'Strategic initiative failure usually involves organizational barriers (clarity, resources, priorities, accountability), not communication or motivation alone. HR''s business consulting role includes diagnosing execution blockers and proposing systematic changes, not just communication fixes.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit is considering a significant technology investment. What should the HR leader consider in advising on this decision?', '["Focus only on hardware and software costs", "Recommend postponing until training is developed", "Understand business case; assess talent/capability implications (will jobs change? Will training be needed?); estimate implementation risks and support requirements", "Estimate HR costs to implement the technology"]'::jsonb, 2, 'Technology investments require consideration of adoption and change management. HR brings perspective on capability gaps, training needs, job design changes, and organizational readiness. This affects implementation success and ROI realization.'),
('shrm-scp', 'Consultation & Business Acumen', 'An organization is deciding whether to centralize or decentralize a key function. How should HR frame the talent implications?', '["Propose a hybrid approach without analyzing trade-offs", "Centralization reduces headcount and cost", "Recommend whatever is cheaper", "Assess both models against business priorities (control, cost, responsiveness); identify talent and capability implications of each; propose governance and service delivery model"]'::jsonb, 3, 'Centralization vs. decentralization decisions have talent implications: centralized creates specialist expertise but slower response; decentralized creates local accountability but may duplicate capabilities. HR should articulate trade-offs aligned to business priorities.'),
('shrm-scp', 'Consultation & Business Acumen', 'A company is experiencing customer attrition and management blames sales team capability. As an HR consultant, what other factors should you suggest investigating?', '["Assume management assessment is correct", "Assess sales strategy (are we targeting the right customers?); product/pricing (is our offering competitive?); service (are we delivering on promises?); understand whether sales capability is truly the issue or a symptom", "Implement aggressive sales incentives", "Propose hiring more experienced salespeople"]'::jsonb, 1, 'Systemic business problems rarely have single causes. Customer attrition could reflect product issues, pricing, service delivery, competitive pressure, or sales execution. HR''s business acumen includes suggesting systemic diagnosis before blaming a function or proposing hiring solutions.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is asked to help develop a business unit''s succession plan for critical leadership roles. What should be included?', '["Recruit only external candidates", "Promote the most senior person regardless of readiness", "Identify potential external candidates", "Assess leadership pipeline (current potential); identify capability gaps; develop high-potential talent; establish readiness timelines; create emergency backup plans; align to business strategy"]'::jsonb, 3, 'Business-focused succession planning aligns talent development to business continuity needs. It assesses internal pipeline, identifies gaps, develops candidates strategically, and establishes clear readiness criteria. This ensures leadership capability supports business strategy.'),
('shrm-scp', 'Consultation & Business Acumen', 'A company''s competitive position is weakening and leadership is considering significant operational changes. What should the HR leader contribute to strategy discussions?', '["Recommend a different strategy based on HR constraints", "Wait for strategy to be decided and implement HR changes afterward", "Assess talent and capability implications of strategy options; identify enablers and risks; propose organizational changes and talent strategies aligned to competitive strategy", "Focus only on implementation details after decisions are made"]'::jsonb, 2, 'Strategic HR leadership means influencing strategy discussions by highlighting talent implications. HR should assess whether talent exists to execute different strategic options, what capability development is needed, and what organizational changes are required. This shapes viable strategies.'),
('shrm-scp', 'Consultation & Business Acumen', 'An HR leader is consulted on organizational design for a new business venture. What should guide recommendations?', '["Understand business model and value creation; assess capability requirements; recommend structure supporting execution and accountability; consider scalability and future evolution", "Design minimizes headcount and cost", "Copy the organizational design from the main company", "Recommend a flat structure without clear roles"]'::jsonb, 0, 'Effective organizational design aligns structure to strategy and business model. HR should design for execution clarity (roles, accountability), capability (matching talent to requirements), and flexibility (scalability). Cookie-cutter or cost-minimized designs often fail to support business execution.'),
('shrm-scp', 'Consultation & Business Acumen', 'A business unit is underperforming against targets. Multiple leaders blame ''poor execution.'' As an HR consultant, what should you propose to diagnose the issue?', '["Assume execution capability is the primary issue", "Recommend performance improvement plans for the team", "Conduct systemic assessment: clarity of goals and accountabilities, capability match to roles, manager effectiveness, resources/tools, competing priorities, consequences/feedback, organizational design", "Propose replacing leadership"]'::jsonb, 2, '''Poor execution'' is a symptom, not a diagnosis. HR''s business consulting role includes identifying root causes using a systemic framework: Do people understand goals? Are they equipped? Are managers coaching? Are there resource barriers? Are roles clear? This diagnosis guides targeted solutions.');